arguments.file_text:
#!/usr/bin/env dotnet
#:property AllowUnsafeBlocks=true

Span<nint> nints = stackalloc nint[4];
for (int i = 0; i < nints.Length; i++)
    nints[i] = i * 10;

Console.WriteLine($"Span<nint> length: {nints.Length}, element size: {nint.Size} bytes");
for (int i = 0; i < nints.Length; i++)
    Console.WriteLine($"  nints[{i}] = {nints[i]}");

Span<nuint> nuints = stackalloc nuint[3];
nuints[0] = nuint.MaxValue;
nuints[1] = 42;
nuints[2] = 0;

Console.WriteLine($"\nSpan<nuint> length: {nuints.Length}, max value: {nuints[0]}");

